import React, { useState, useEffect, useCallback } from 'react';
import { PageBanner, NavPills, ScoreCard, SvgGauge, SectionHeader, DataTable, Spinner, Footer } from '../components/UIComponents';
import { getMaturityQuestions, submitMaturity, downloadMaturityExcel, downloadMaturityPDF } from '../utils/api';

/* ═══════════════════════════════════════════════════════════════
   QUESTION BANK — mirrors backend DataMaturity/config.py exactly
   ═══════════════════════════════════════════════════════════════ */
const QUESTION_BANK = {
  "Data Governance": [
    { id: "DG-1",  section: "Data Management Strategy (DMS)", question: "Documented Data Management Strategy exists (vision, scope, objectives).", weight: 2 },
    { id: "DG-2",  section: "Data Management Strategy (DMS)", question: "Stakeholders are involved in strategy creation and review.", weight: 1 },
    { id: "DG-3",  section: "Data Management Strategy (DMS)", question: "Strategy is approved, published, and communicated to relevant stakeholders.", weight: 1 },
    { id: "DG-4",  section: "Roles & Responsibilities", question: "Data roles (Owner, Steward, Custodian) are defined for the object.", weight: 2 },
    { id: "DG-5",  section: "Roles & Responsibilities", question: "Roles and responsibilities are documented and communicated.", weight: 1 },
    { id: "DG-6",  section: "Policies & Standards", question: "Governance policies/standards exist (naming, definitions, approvals).", weight: 2 },
    { id: "DG-7",  section: "Policies & Standards", question: "Policies are periodically reviewed and updated.", weight: 1 },
    { id: "DG-8",  section: "DMO", question: "Data Management Office (DMO) / governance forum exists.", weight: 2 },
    { id: "DG-9",  section: "DMO", question: "Operating model & governance cadence are defined (RACI, forums, KPIs).", weight: 1 },
    { id: "DG-10", section: "Change Management", question: "Change control process exists for master data requests/updates.", weight: 2 },
    { id: "DG-11", section: "Change Management", question: "Training / enablement exists for users and data stewards.", weight: 1 },
    { id: "DG-12", section: "Issue Management", question: "Issue logging, triage, and resolution workflow exists.", weight: 1 },
    { id: "DG-13", section: "Issue Management", question: "Root-cause analysis and lessons learned are captured.", weight: 1 },
    { id: "DG-14", section: "Metadata", question: "Metadata (definitions, owners, rules) is managed in a repository/catalog.", weight: 1 },
  ],
  "Data Quality": [
    { id: "DQ-1",  section: "Assessment & Rules", question: "Data quality assessment policy exists (what, how often, ownership).", weight: 2 },
    { id: "DQ-2",  section: "Assessment & Rules", question: "DQ rules are defined (completeness, validity, uniqueness, consistency).", weight: 2 },
    { id: "DQ-3",  section: "Assessment & Rules", question: "DQ rules cover critical fields and are documented with thresholds.", weight: 2 },
    { id: "DQ-4",  section: "Monitoring", question: "DQ monitoring is periodic and tracked (dashboards/scorecards).", weight: 2 },
    { id: "DQ-5",  section: "Monitoring", question: "Automated validation exists (API checks, format checks, reference checks).", weight: 1 },
    { id: "DQ-6",  section: "Duplicates", question: "Duplicate detection & golden record process exists.", weight: 2 },
    { id: "DQ-7",  section: "Profiling", question: "Data profiling is performed using tools/standard techniques.", weight: 1 },
    { id: "DQ-8",  section: "Profiling", question: "Anomalies/inconsistencies are identified and resolved consistently.", weight: 1 },
    { id: "DQ-9",  section: "Standardization", question: "Standardization rules exist (formats, naming conventions, codes).", weight: 2 },
    { id: "DQ-10", section: "Standardization", question: "Uniform definitions and formatting are applied across datasets/systems.", weight: 1 },
    { id: "DQ-11", section: "Cleansing", question: "Cleansing workflow/tools exist (issue queues, approvals, audit trail).", weight: 2 },
    { id: "DQ-12", section: "Cleansing", question: "Recurring cleansing is planned (not only ad-hoc one-time fixes).", weight: 1 },
  ],
  "Data Integration & Interoperability": [
    { id: "DI-1", section: "Integration Strategy & Architecture", question: "Enterprise-wide integration strategy exists (APIs/ETL/events), aligned to target state.", weight: 2 },
    { id: "DI-2", section: "Integration Strategy & Architecture", question: "System of Record (SoR) / System of Entry is clearly defined per object.", weight: 2 },
    { id: "DI-3", section: "Integration Strategy & Architecture", question: "Integration flows and interfaces are documented (source-to-target mapping).", weight: 2 },
    { id: "DI-4", section: "Integration Technology & Tools", question: "Integration platform/tooling supports scalability & performance requirements.", weight: 1 },
    { id: "DI-5", section: "Integration Technology & Tools", question: "Logging, monitoring, reconciliation, and audit trails exist for data movement.", weight: 2 },
  ],
};

const RATING_LABELS = ["Adhoc", "Repeatable", "Defined", "Managed", "Optimised"];
const DEFAULT_OBJECTS = ['Customer', 'Vendor Master', 'Item Master', 'Price', 'Finance'];
const DIMS_LIST = Object.keys(QUESTION_BANK);

/* ── Build initial grid data from question bank ── */
function buildGridData(qBank, objectsList) {
  const data = {};
  Object.entries(qBank).forEach(([dim, qList]) => {
    data[dim] = qList.map(q => {
      const row = { id: q.id, section: q.section, question: q.question, weight: q.weight };
      objectsList.forEach(obj => { row[obj] = RATING_LABELS[0]; }); // Default "Adhoc"
      return row;
    });
  });
  return data;
}

/* ═══════════════════════════════════════════════════════════
   Editable Grid Table — matches Streamlit st.data_editor
   ═══════════════════════════════════════════════════════════ */
function EditableGrid({ rows, objects, onChange, fullView }) {
  const maxH = fullView ? 'none' : '520px';
  return (
    <div style={{ overflowX: 'auto', overflowY: fullView ? 'visible' : 'auto', maxHeight: maxH, border: '1.5px solid #d9cef0', borderRadius: 10, background: '#fff' }}>
      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.82rem', fontFamily: "'Plus Jakarta Sans', sans-serif" }}>
        <thead>
          <tr style={{ position: 'sticky', top: 0, zIndex: 2 }}>
            {['Question ID', 'Section', 'Question', 'Weight'].concat(objects).map((col, ci) => (
              <th key={col} style={{
                background: '#ede8f7', color: '#3b1f72', fontWeight: 700, fontSize: '0.78rem',
                padding: '0.55rem 0.6rem', textAlign: ci === 2 ? 'left' : 'center',
                borderBottom: '2px solid #d9cef0', borderRight: '1px solid #e8e2f5',
                whiteSpace: 'nowrap', position: 'sticky', top: 0,
                minWidth: ci === 0 ? 85 : ci === 1 ? 160 : ci === 2 ? 320 : ci === 3 ? 55 : 105,
              }}>{col}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.map((row, ri) => (
            <tr key={row.id + '-' + ri} style={{ borderBottom: '1px solid #f0ebfa' }}
              onMouseEnter={e => e.currentTarget.style.background = '#faf8ff'}
              onMouseLeave={e => e.currentTarget.style.background = ''}>
              {/* Question ID — read only */}
              <td style={{ padding: '0.45rem 0.5rem', textAlign: 'center', fontWeight: 600, color: '#5b2d90', fontSize: '0.78rem', borderRight: '1px solid #f0ebfa', whiteSpace: 'nowrap' }}>
                {row.id}
              </td>
              {/* Section — read only */}
              <td style={{ padding: '0.45rem 0.5rem', color: '#555', fontSize: '0.78rem', borderRight: '1px solid #f0ebfa' }}>
                {row.section}
              </td>
              {/* Question — read only */}
              <td style={{ padding: '0.45rem 0.6rem', color: '#1a1a2e', lineHeight: 1.4, borderRight: '1px solid #f0ebfa' }}>
                {row.question}
              </td>
              {/* Weight — read only */}
              <td style={{ padding: '0.45rem 0.4rem', textAlign: 'center', fontWeight: 600, color: '#7a7a9a', fontSize: '0.8rem', borderRight: '1px solid #f0ebfa' }}>
                {row.weight.toFixed(1)}
              </td>
              {/* Object rating columns — EDITABLE dropdowns */}
              {objects.map(obj => {
                const val = row[obj] || RATING_LABELS[0];
                const colorMap = { 'Adhoc': '#64748b', 'Repeatable': '#b45309', 'Defined': '#1d4ed8', 'Managed': '#5b2d90', 'Optimised': '#0f766e' };
                return (
                  <td key={obj} style={{ padding: '0.3rem 0.25rem', textAlign: 'center', borderRight: '1px solid #f0ebfa' }}>
                    <select value={val} onChange={e => onChange(ri, obj, e.target.value)} style={{
                      width: '100%', padding: '0.3rem 0.2rem', border: '1.5px solid #d9cef0',
                      borderRadius: 6, fontSize: '0.76rem', fontWeight: 600, fontFamily: 'inherit',
                      color: colorMap[val] || '#5b2d90', background: val === 'Adhoc' ? '#fff' : '#f8f6ff',
                      cursor: 'pointer', outline: 'none',
                    }}>
                      {RATING_LABELS.map(r => <option key={r} value={r} style={{ color: colorMap[r] }}>{r}</option>)}
                    </select>
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════
   MAIN COMPONENT
   ═══════════════════════════════════════════════════════════ */
export default function MaturityPage({ onNavigate, sessionId, dqScore }) {
  const [clientName, setClientName] = useState('');
  const [objects, setObjects] = useState([...DEFAULT_OBJECTS]);
  const [mastersApplicable, setMastersApplicable] = useState(true);
  const [benchmark, setBenchmark] = useState(3.0);
  const [target, setTarget] = useState(3.0);
  const [lowThr, setLowThr] = useState(2.0);

  const [gridData, setGridData] = useState(() => buildGridData(QUESTION_BANK, DEFAULT_OBJECTS));
  const [activeDim, setActiveDim] = useState(DIMS_LIST[0]);
  const [fullView, setFullView] = useState({});
  const [entryTab, setEntryTab] = useState('manual'); // 'manual' | 'upload'

  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [results, setResults] = useState(null);
  const [error, setError] = useState('');
  const [apiStatus, setApiStatus] = useState('offline');

  const currentObjects = mastersApplicable ? objects : [clientName || 'Overall'];

  // Try connecting to backend
  useEffect(() => {
    (async () => {
      try {
        const resp = await getMaturityQuestions([], []);
        if (resp.data.questions && Object.keys(resp.data.questions).length > 0) setApiStatus('connected');
      } catch { setApiStatus('offline'); }
    })();
  }, []);

  // Rebuild grid when objects change
  useEffect(() => {
    setGridData(prev => {
      const updated = { ...prev };
      Object.keys(updated).forEach(dim => {
        updated[dim] = updated[dim].map(row => {
          const nr = { ...row };
          currentObjects.forEach(obj => { if (!(obj in nr)) nr[obj] = RATING_LABELS[0]; });
          return nr;
        });
      });
      return updated;
    });
  }, [currentObjects.join(',')]);

  /* ── Grid cell change ── */
  const handleCellChange = useCallback((dim, rowIdx, obj, value) => {
    setGridData(prev => {
      const u = { ...prev };
      const rows = [...u[dim]];
      rows[rowIdx] = { ...rows[rowIdx], [obj]: value };
      u[dim] = rows;
      return u;
    });
  }, []);

  /* ── Add Question ── */
  const addQuestion = (dim) => {
    setGridData(prev => {
      const u = { ...prev };
      const rows = [...u[dim]];
      const newRow = { id: `CQ-${rows.length + 1}`, section: 'Custom', question: 'Enter question text…', weight: 1 };
      currentObjects.forEach(obj => { newRow[obj] = RATING_LABELS[0]; });
      u[dim] = [...rows, newRow];
      return u;
    });
  };

  /* ── Remove Last ── */
  const removeLast = (dim) => {
    setGridData(prev => {
      const u = { ...prev };
      if (u[dim].length > 1) u[dim] = u[dim].slice(0, -1);
      return u;
    });
  };

  /* ── Count filled (non-Adhoc) ── */
  const countFilled = (dim) => {
    const rows = gridData[dim] || [];
    let filled = 0, total = 0;
    rows.forEach(r => { currentObjects.forEach(obj => { total++; if (r[obj] && r[obj] !== RATING_LABELS[0]) filled++; }); });
    return { filled, total };
  };

  /* ── Build submission payload ── */
  const buildResponsePayload = () => {
    const payload = {};
    DIMS_LIST.forEach(dim => {
      payload[dim] = (gridData[dim] || []).map(row => {
        const r = { 'Question': row.question, 'Question ID': row.id, 'Section': row.section, 'Weight': row.weight };
        currentObjects.forEach(obj => {
          const val = row[obj] || RATING_LABELS[0];
          const idx = RATING_LABELS.indexOf(val);
          r[obj] = String(idx >= 0 ? idx + 1 : 1); // Convert label to numeric string
        });
        return r;
      });
    });
    return payload;
  };

  /* ── Submit ── */
  const handleSubmit = async () => {
    if (!clientName.trim()) { setError('Please enter a Client Name.'); return; }
    setLoading(true); setError('');
    try {
      const resp = await submitMaturity({
        session_id: sessionId, client_name: clientName, dims: DIMS_LIST,
        objects: currentObjects, responses: buildResponsePayload(),
        benchmark, target, low_thr: lowThr, dq_score: dqScore,
      });
      setResults(resp.data); setSubmitted(true);
    } catch (e) {
      setError(e.response?.data?.error || e.message);
    } finally { setLoading(false); }
  };

  const tp = DIMS_LIST.reduce((a, d) => { const c = countFilled(d); return { filled: a.filled + c.filled, total: a.total + c.total }; }, { filled: 0, total: 0 });

  /* ═══════════════════════════════════════════════════════════
     RENDER
     ═══════════════════════════════════════════════════════════ */
  return (
    <div className="page-maturity">
      <PageBanner icon="📈" badge="DAMA Framework" title="Data Maturity Assessment"
        subtitle="Evaluate maturity across DAMA dimensions — governance, quality, architecture, integration & privacy — with weighted scoring and benchmarking." />
      <NavPills current="maturity" onChange={onNavigate} />

      {loading && <Spinner message="Computing scores and building reports..." />}
      {error && <div className="error-banner" onClick={() => setError('')} style={{ cursor: 'pointer' }}>⚠️ {error} <span style={{ float: 'right', fontWeight: 700 }}>✕</span></div>}

      {/* ═══════ RESULTS ═══════ */}
      {submitted && results && !loading && (
        <div className="maturity-results">
          {/* Edit button top-right */}
          <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: '0.5rem' }}>
            <button className="btn-primary" onClick={() => { setSubmitted(false); setResults(null); }}>✏️ Edit Responses</button>
          </div>

          {dqScore != null && <div className="dq-score-banner"><strong>DQ Score:</strong> {dqScore.toFixed(1)}% → <strong>Level:</strong> {results.dq_maturity_level}</div>}

          {/* Summary Slide */}
          <h3 className="subsection-title">📊 Summary Slide</h3>
          {results.slide_png_b64 && <div className="slide-wrap"><img src={`data:image/png;base64,${results.slide_png_b64}`} alt="Summary" style={{ width: '100%', borderRadius: 14 }} /></div>}

          {/* ── Dimension-wise Maturity Table ── */}
          {results.dim_table && (
            <div style={{ background: '#fff', border: '1.5px solid #d9cef0', borderRadius: 16, padding: '1.2rem 1.4rem 1rem', margin: '1.2rem 0', boxShadow: '0 2px 12px rgba(91,45,144,0.07)' }}>
              <div style={{ fontSize: '1rem', fontWeight: 700, color: '#3b1f72', marginBottom: '0.75rem', paddingBottom: '0.5rem', borderBottom: '2px solid #ede8f7' }}>
                📐 Dimension-wise Maturity
              </div>
              <div style={{ overflowX: 'auto' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: "'Plus Jakarta Sans', sans-serif" }}>
                  <thead>
                    <tr>
                      <th style={{ background: '#5b2d90', color: '#fff', padding: '0.6rem 1rem', textAlign: 'left', fontSize: '0.82rem', fontWeight: 700 }}></th>
                      {currentObjects.map(obj => (
                        <th key={obj} style={{ background: '#5b2d90', color: '#fff', padding: '0.6rem 0.8rem', textAlign: 'center', fontSize: '0.82rem', fontWeight: 700 }}>{obj}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(results.dim_table).map(([dim, vals], ri) => (
                      <tr key={dim} style={{ background: ri % 2 === 0 ? '#fff' : '#ede8f7' }}>
                        <td style={{ padding: '0.55rem 1rem', fontWeight: 600, color: '#1a1a2e', fontSize: '0.84rem' }}>{dim}</td>
                        {currentObjects.map(obj => {
                          const v = vals[obj];
                          const num = typeof v === 'number' ? v : parseFloat(v) || 0;
                          const bg = num >= 4 ? '#dcfce7' : num >= 3 ? '#dbeafe' : num >= 2 ? '#fef3c7' : '#fff';
                          return (
                            <td key={obj} style={{ padding: '0.55rem 0.8rem', textAlign: 'center', fontWeight: 700, fontSize: '0.9rem', color: '#1a1a2e', background: bg }}>
                              {num.toFixed(2)}
                            </td>
                          );
                        })}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ── Overall Maturity Score Table ── */}
          {results.overall && (
            <div style={{ background: '#fff', border: '1.5px solid #d9cef0', borderRadius: 16, padding: '1.2rem 1.4rem 1rem', margin: '1.2rem 0', boxShadow: '0 2px 12px rgba(91,45,144,0.07)' }}>
              <div style={{ fontSize: '1rem', fontWeight: 700, color: '#3b1f72', marginBottom: '0.75rem', paddingBottom: '0.5rem', borderBottom: '2px solid #ede8f7' }}>
                🏆 Overall Maturity Score
              </div>
              <div style={{ overflowX: 'auto' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: "'Plus Jakarta Sans', sans-serif" }}>
                  <thead>
                    <tr>
                      <th style={{ background: '#5b2d90', color: '#fff', padding: '0.6rem 1rem', textAlign: 'center', fontSize: '0.82rem', fontWeight: 700 }}>Master Data Object</th>
                      <th style={{ background: '#5b2d90', color: '#fff', padding: '0.6rem 1rem', textAlign: 'center', fontSize: '0.82rem', fontWeight: 700 }}>Score</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(results.overall).map(([obj, score], ri) => {
                      const num = typeof score === 'number' ? score : parseFloat(score) || 0;
                      const bg = ri % 2 === 0 ? '#fff' : '#ede8f7';
                      return (
                        <tr key={obj} style={{ background: bg }}>
                          <td style={{ padding: '0.55rem 1rem', textAlign: 'center', fontWeight: 600, color: '#1a1a2e', fontSize: '0.84rem' }}>{obj}</td>
                          <td style={{ padding: '0.55rem 1rem', textAlign: 'center', fontWeight: 700, color: '#1a1a2e', fontSize: '0.9rem' }}>{num.toFixed(2)}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ── Horizontal Bar Chart (Maturity Scale) ── */}
          {results.domain_scores && (
            <div style={{ background: '#f5f0fc', border: '1.5px solid #d9cef0', borderRadius: 16, padding: '1.4rem 1.6rem', margin: '1.2rem 0' }}>
              <div style={{ fontSize: '1rem', fontWeight: 700, color: '#3b1f72', marginBottom: '1rem' }}>📊 Maturity Bar Chart</div>
              {(() => {
                const barColors = { 1: '#64748b', 2: '#b45309', 3: '#1d4ed8', 4: '#5b2d90', 5: '#0f766e' };
                const getColor = (s) => barColors[Math.max(1, Math.min(5, Math.round(s)))] || '#5b2d90';
                const entries = Object.entries(results.domain_scores);
                return (
                  <div>
                    {entries.map(([dim, score]) => {
                      const s = typeof score === 'number' ? score : parseFloat(score) || 1;
                      const pct = Math.min((s / 5) * 100, 100);
                      return (
                        <div key={dim} style={{ display: 'flex', alignItems: 'center', marginBottom: '0.8rem', gap: '0.8rem' }}>
                          <div style={{ width: 250, textAlign: 'right', fontSize: '0.84rem', fontWeight: 600, color: '#0c4a6e', flexShrink: 0 }}>{dim}</div>
                          <div style={{ flex: 1, position: 'relative', height: 28, background: '#e9e4f5', borderRadius: 6, overflow: 'hidden' }}>
                            <div style={{ width: `${pct}%`, height: '100%', background: getColor(s), borderRadius: 6, transition: 'width 0.5s' }} />
                            {/* Benchmark line at 3.0 */}
                            <div style={{ position: 'absolute', left: '60%', top: 0, bottom: 0, width: 2, background: '#38bdf8', opacity: 0.7 }} />
                            {/* Managed line at 4.0 */}
                            <div style={{ position: 'absolute', left: '80%', top: 0, bottom: 0, width: 2, background: '#0284c7', opacity: 0.7 }} />
                          </div>
                          <div style={{ width: 50, fontWeight: 800, fontSize: '0.95rem', color: '#3d1d63' }}>{s.toFixed(2)}</div>
                        </div>
                      );
                    })}
                    {/* Axis */}
                    <div style={{ display: 'flex', alignItems: 'center', marginTop: '0.3rem', gap: '0.8rem' }}>
                      <div style={{ width: 250 }} />
                      <div style={{ flex: 1, display: 'flex', justifyContent: 'space-between', fontSize: '0.72rem', color: '#7a7a9a', fontWeight: 600 }}>
                        {[0, 1, 2, 3, 4, 5, 6].map(n => <span key={n}>{n}</span>)}
                      </div>
                      <div style={{ width: 50 }} />
                    </div>
                    <div style={{ textAlign: 'center', fontSize: '0.78rem', fontWeight: 600, color: '#0c4a6e', marginTop: '0.3rem' }}>
                      Maturity Score (1=Adhoc → 5=Optimised)
                    </div>
                    {/* Legend */}
                    <div style={{ display: 'flex', gap: '0.8rem', justifyContent: 'flex-end', marginTop: '0.8rem', flexWrap: 'wrap' }}>
                      {[
                        ['#64748b', '1-Adhoc'], ['#b45309', '2-Repeatable'], ['#1d4ed8', '3-Defined'],
                        ['#5b2d90', '4-Managed'], ['#0f766e', '5-Optimised'],
                      ].map(([c, l]) => (
                        <div key={l} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                          <div style={{ width: 14, height: 14, borderRadius: 3, background: c }} />
                          <span style={{ fontSize: '0.72rem', fontWeight: 600, color: '#555' }}>{l}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })()}
            </div>
          )}

          {/* ── Gauge donuts ── */}
          <div className="gauges-row">
            {Object.entries(results.domain_scores || {}).map(([d, s]) => {
              const num = typeof s === 'number' ? s : parseFloat(s) || 0;
              return <SvgGauge key={d} score={Math.min(num * 20, 100)} label={d} />;
            })}
          </div>

          {/* ── Downloads ── */}
          <SectionHeader>📥 Download Reports</SectionHeader>
          <div className="download-row">
            <div className="download-card">
              <div className="dl-icon">📄</div>
              <div className="dl-title">PDF Maturity Report</div>
              <div className="dl-desc">Executive maturity summary slide, domain scoring, and detailed question-level scoring.</div>
              <a href={downloadMaturityPDF(sessionId)} className="btn-primary" download>⬇ Download PDF</a>
            </div>
            <div className="download-card">
              <div className="dl-icon">📊</div>
              <div className="dl-title">Excel Workbook</div>
              <div className="dl-desc">Multi-sheet: dimension summary, overall maturity, question responses, exception sheets.</div>
              <a href={downloadMaturityExcel(sessionId)} className="btn-primary" download>⬇ Download Excel</a>
            </div>
          </div>

          <div style={{ textAlign: 'center', marginTop: '1.5rem' }}>
            <button className="btn-secondary" onClick={() => { setSubmitted(false); setResults(null); }}>✏️ Edit Responses</button>
          </div>
        </div>
      )}

      {/* ═══════ FORM ═══════ */}
      {!submitted && !loading && (
        <div className="maturity-form">
          {/* ──── SIDEBAR ──── */}
          <div className="mat-sidebar">
            <div className="sidebar-section">
              <h4>⚙️ Configuration</h4>
              <label className="form-label">Client Name <span className="required">*</span>
                <input type="text" value={clientName} onChange={e => setClientName(e.target.value)} placeholder="Organisation name (required)" />
              </label>
              {!clientName.trim() && <p className="field-error">⚠ Required</p>}
            </div>

            <div className="sidebar-section">
              <div style={{ background: 'linear-gradient(135deg,#f5f0fc,#fdf2f8)', border: '2px solid #b09dd6', borderRadius: 12, padding: '0.65rem 0.8rem', boxShadow: '0 2px 10px rgba(91,45,144,0.12)' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.25rem' }}>
                  <span style={{ fontSize: '1.1rem' }}>📋</span>
                  <span style={{ fontSize: '0.88rem', fontWeight: 800, color: '#3b1f72' }}>Masters Applicable</span>
                </div>
                <p style={{ fontSize: '0.76rem', color: '#5b2d90', margin: '0 0 0.4rem', lineHeight: 1.4 }}>Enable to evaluate maturity per Master Data Object</p>
                <label className="checkbox-label" style={{ marginBottom: 0 }}>
                  <input type="checkbox" checked={mastersApplicable} onChange={e => setMastersApplicable(e.target.checked)} />
                  Include Master Data Objects in assessment
                </label>
              </div>
            </div>

            {mastersApplicable && (
              <div className="sidebar-section">
                <label className="form-label">Master Data Objects
                  <select multiple value={objects} onChange={e => setObjects(Array.from(e.target.selectedOptions, o => o.value))} style={{ height: 140 }}>
                    {DEFAULT_OBJECTS.map(o => <option key={o}>{o}</option>)}
                  </select>
                </label>
              </div>
            )}

            <div className="sidebar-section">
              <label className="form-label">Maturity Dimensions</label>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {DIMS_LIST.map(d => (
                  <span key={d} style={{ background: '#5b2d90', color: '#fff', fontSize: '0.7rem', fontWeight: 700, padding: '3px 8px', borderRadius: 999 }}>
                    {d} ✕
                  </span>
                ))}
              </div>
            </div>

            <div className="sidebar-section">
              <label className="form-label">Industry Benchmark<input type="number" min="1" max="5" step="0.1" value={benchmark} onChange={e => setBenchmark(parseFloat(e.target.value) || 3)} /></label>
              <label className="form-label">Target Score<input type="number" min="1" max="5" step="0.1" value={target} onChange={e => setTarget(parseFloat(e.target.value) || 3)} /></label>
              <label className="form-label">Exception Threshold (≤)<input type="range" min="1" max="5" step="0.5" value={lowThr} onChange={e => setLowThr(parseFloat(e.target.value))} /><span className="range-val">{lowThr}</span></label>
            </div>

            <div style={{ fontSize: '0.72rem', padding: '0.35rem 0.5rem', borderRadius: 8, textAlign: 'center', marginTop: 4, border: '1px solid', borderColor: apiStatus === 'connected' ? '#bbf7d0' : '#fde68a', background: apiStatus === 'connected' ? '#f0fdf4' : '#fffbeb', color: apiStatus === 'connected' ? '#059669' : '#d97706' }}>
              {apiStatus === 'connected' ? '🟢 Backend connected' : '🟡 Offline mode'}
            </div>
          </div>

          {/* ──── MAIN CONTENT ──── */}
          <div className="mat-main">
            {/* Assessment Entry Header */}
            <div style={{ background: 'linear-gradient(135deg,#f5f0fc,#fdf2f8)', border: '1.5px solid #d9cef0', borderRadius: 14, padding: '1rem 1.4rem 0.8rem', marginBottom: '1rem' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', marginBottom: '0.3rem' }}>
                <span style={{ fontSize: '1.3rem' }}>✏️</span>
                <span style={{ fontSize: '1rem', fontWeight: 800, color: '#3b1f72' }}>Assessment Entry</span>
              </div>
              <p style={{ fontSize: '0.85rem', color: '#5b2d90', margin: 0, lineHeight: 1.5 }}>
                Rate each question per Master Data Object using the dropdown selectors in the grid below,
                or use <strong>Upload Template</strong> to fill offline and import responses.
              </p>
            </div>

            {/* Manual Entry / Upload Template Tabs */}
            <div className="tab-bar">
              <button className={`tab-btn ${entryTab === 'manual' ? 'active' : ''}`} onClick={() => setEntryTab('manual')}>✏️ Manual Entry</button>
              <button className={`tab-btn ${entryTab === 'upload' ? 'active' : ''}`} onClick={() => setEntryTab('upload')}>📤 Upload Template</button>
            </div>

            {entryTab === 'manual' && (
              <>
                {/* Dimension Tabs */}
                <div className="tab-bar" style={{ marginTop: 0, borderBottom: '2px solid #d9cef0' }}>
                  {DIMS_LIST.map(d => {
                    const { filled, total } = countFilled(d);
                    return (
                      <button key={d} className={`tab-btn ${activeDim === d ? 'active' : ''}`} onClick={() => setActiveDim(d)} style={{ fontSize: '0.82rem' }}>
                        {d}
                        <span style={{ marginLeft: 5, fontSize: '0.65rem', fontWeight: 700, background: filled > 0 ? '#5b2d90' : '#e8e2f5', color: filled > 0 ? '#fff' : '#7a7a9a', borderRadius: 999, padding: '1px 5px' }}>{filled}/{total}</span>
                      </button>
                    );
                  })}
                </div>

                {/* Action Buttons: Add Question / Remove Last / Full View */}
                <div style={{ display: 'flex', gap: '0.5rem', margin: '0.6rem 0' }}>
