                  <button onClick={() => removeLast(activeDim)} style={{ flex: 1, padding: '0.45rem 0.8rem', border: '1.5px solid #d9cef0', borderRadius: 8, background: '#fff', color: '#3b1f72', fontWeight: 600, fontSize: '0.82rem', cursor: 'pointer' }}>
                    ➖ Remove Last
                  </button>
                  <button onClick={() => setFullView(p => ({ ...p, [activeDim]: !p[activeDim] }))} style={{ flex: 1, padding: '0.45rem 0.8rem', border: '1.5px solid #d9cef0', borderRadius: 8, background: '#fff', color: '#3b1f72', fontWeight: 600, fontSize: '0.82rem', cursor: 'pointer' }}>
                    {fullView[activeDim] ? '◱ Compact' : '⛶ Full View'}
                  </button>
                </div>

                {/* ═══ THE GRID ═══ */}
                <EditableGrid
                  rows={gridData[activeDim] || []}
                  objects={currentObjects}
                  onChange={(ri, obj, val) => handleCellChange(activeDim, ri, obj, val)}
                  fullView={!!fullView[activeDim]}
                />
              </>
            )}

            {entryTab === 'upload' && (
              <div style={{ padding: '1.5rem', textAlign: 'center' }}>
                <p style={{ fontSize: '0.85rem', color: '#555', marginBottom: '1rem', lineHeight: 1.5 }}>
                  Download the Excel template, fill in ratings offline, then upload the completed file here to import all responses into the assessment grid.
                </p>
                <div style={{ background: '#f9f8fc', border: '1.5px solid #e8e2f5', borderRadius: 10, padding: '0.7rem 1rem', marginBottom: '1rem', textAlign: 'left' }}>
                  <span style={{ fontSize: '0.85rem', fontWeight: 700, color: '#3b1f72' }}>Step 1: </span>
                  <span style={{ fontSize: '0.84rem', color: '#555' }}>Download the template with current questions and objects</span>
                </div>
                <button className="btn-secondary" style={{ marginBottom: '1.5rem' }}>⬇ Download Excel Template</button>
                <div style={{ background: '#f9f8fc', border: '1.5px solid #e8e2f5', borderRadius: 10, padding: '0.7rem 1rem', marginBottom: '1rem', textAlign: 'left' }}>
                  <span style={{ fontSize: '0.85rem', fontWeight: 700, color: '#3b1f72' }}>Step 2: </span>
                  <span style={{ fontSize: '0.84rem', color: '#555' }}>Upload the filled template to import responses</span>
                </div>
                <div style={{ border: '2.5px dashed #d9cef0', borderRadius: 16, padding: '2rem', background: 'linear-gradient(135deg,#f5f0fc,#fdf2f8)', cursor: 'pointer' }}>
                  <p style={{ fontSize: '0.9rem', color: '#5b2d90', fontWeight: 600 }}>📤 Click to upload or drag .xlsx file here</p>
                  <p style={{ fontSize: '0.78rem', color: '#7a7a9a' }}>Supports .xlsx and .xls files</p>
                </div>
              </div>
            )}

            {/* Progress Bar */}
            <div style={{ background: 'linear-gradient(135deg,#f5f0fc,#fdf2f8)', border: '1.5px solid #d9cef0', borderRadius: 10, padding: '0.6rem 1rem', margin: '0.8rem 0', fontSize: '0.82rem', color: '#3b1f72' }}>
              <strong>Overall progress:</strong> {tp.filled} / {tp.total} cells rated ({tp.total > 0 ? Math.round(tp.filled / tp.total * 100) : 0}%)
              <div style={{ marginTop: 4, height: 6, background: '#e8e2f5', borderRadius: 999, overflow: 'hidden' }}>
                <div style={{ width: `${tp.total > 0 ? (tp.filled / tp.total * 100) : 0}%`, height: '100%', borderRadius: 999, background: 'linear-gradient(90deg,#5b2d90,#b10f74)', transition: 'width 0.3s' }} />
              </div>
            </div>

            {/* Submit */}
            <div className="submit-section">
              <button className="btn-run" onClick={handleSubmit} disabled={!clientName.trim() || loading}>
                ✅ Submit & Generate Report
              </button>
            </div>
          </div>
        </div>
      )}

      <Footer />
    </div>
  );
}
